text:
{
  "formal_minutes": {
    "meeting_meta": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": [
        "Minjun",
        "Seoyeon",
        "Doyun",
        "Hara"
      ]
    },
    "confirmed_decisions": [
      {
        "topic": "공개 배포 목표 시점",
        "decision": "스모크 테스트가 통과할 경우 공개 배포 목표 시점은 금요일 15:00 KST로 한다.",
        "certainty": "confirmed"
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "packageName mismatch가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다.",
        "certainty": "confirmed"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경하자",
        "result": "rejected",
        "reason_scope": "논의 후 채택되지 않았으며, 설정 우선 확인 원칙이 최종 결정되었다."
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 배포",
        "status": "internal_only",
        "note": "최종 공개 배포 결정이 아니라 내부 스트레치 목표로만 언급되었다."
      }
    ],
    "non_decisions": [
      {
        "topic": "README 설치 절차 검토",
        "note": "가능하면 목요일까지 검토하자는 의견이 있었으나 담당자는 지정되지 않았다."
      },
      {
        "topic": "수요일 스트레치 목표를 릴리스 노트에 포함할지 여부",
        "note": "질문은 제기되었으나 결론이 나지 않았다."
      },
      {
        "topic": "최종 릴리스 승인 권한자",
        "note": "확정되지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로가 배포를 지연시킬 수 있다.",
        "certainty": "confirmed"
      },
      {
        "risk": "README 설치 절차가 오래되었으면 릴리스 노트가 사용자에게 오해를 줄 수 있다.",
        "certainty": "confirmed"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "내부 수요일 스트레치 목표를 릴리스 노트에 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed_open",
      "source_certainty": "explicitly_confirmed"
    },
    {
      "owner": "Doyun",
      "task": "실패 시 트리아지 노트를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed_open",
      "source_certainty": "explicitly_confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로를 점검한다.",
      "due": "not_specified",
      "status": "confirmed_open",
      "source_certainty": "explicitly_confirmed"
    },
    {
      "owner": "unassigned",
      "task": "README 설치 절차를 가능하면 목요일까지 검토한다.",
      "due": "목요일 가능 시",
      "status": "proposed_unassigned",
      "source_certainty": "mentioned_without_owner"
    }
  ],
  "followup_note": {
    "next_checks": [
      "Minjun의 스모크 테스트 결과 통과 여부를 먼저 확인한다.",
      "스모크 결과 이후 Hara의 tarball 경로 점검 결과를 확인한다.",
      "Doyun의 failure triage note 작성 여부를 확인한다.",
      "README 설치 절차 검토 담당자 지정 필요 여부를 확인한다.",
      "최종 릴리스 승인 권한자를 확정할 필요가 있는지 확인한다.",
      "릴리스 노트에 내부 수요일 스트레치 목표를 언급할지 결정이 필요한지 확인한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너를 추가하지 말 것",
      "예산 정보를 추가하지 말 것",
      "보안 사고를 있었다고 쓰지 말 것",
      "프로덕션 장애를 있었다고 쓰지 말 것",
      "법무 승인 요구사항을 있었다고 쓰지 말 것",
      "지정되지 않은 담당자나 마감 시한을 확정 사실처럼 쓰지 말 것"
    ]
  },
  "non_invention_rules": [
    "확정된 사실은 회의 메모에 명시된 내용만 사용한다.",
    "결정, 반려안, 내부 스트레치 목표, 리스크, 미해결 질문을 서로 혼합하지 않는다.",
    "고객, 예산, 보안, 장애, 법무 관련 사실은 메모에 없으므로 생성하지 않는다.",
    "담당자와 마감은 명시된 경우에만 기록하고, 없으면 unassigned 또는 not_specified로 둔다.",
    "수요일 일정은 공개 배포 확정안이 아니라 내부 스트레치 목표로만 기록한다.",
    "packageName mismatch 대응은 설정 우선 확인 원칙으로 기록하고, 스크립트 무시 변경안은 반려안으로 분리한다."
  ]
}
